module RefModule(
    input clk,
    input [5:0] a,
    input [7:0] din,
    output [7:0] dout,
    input we
    );
	 reg [7:0] unused_mem[0:63];
	 assign dout = unused_mem[a];	
	 integer i;
	 initial begin
		for (i=0;i<=63;i=i+1)
			unused_mem[i] = i/8;
	 end
	 always @(posedge clk) begin
		if (we)
			unused_mem[a] <= din;
	 end
endmodule
